type UnescapedCookieParamError struct {
	ParamName string
	Err       error
}

func (e *UnescapedCookieParamError) Error() string {
	return fmt.Sprintf("error unescaping cookie parameter '%s'", e.ParamName)
}

func (e *UnescapedCookieParamError) Unwrap() error {
	return e.Err
}

type UnmarshalingParamError struct {
	ParamName string
	Err       error
}

func (e *UnmarshalingParamError) Error() string {
	return fmt.Sprintf("Error unmarshaling parameter %s as JSON: %s", e.ParamName, e.Err.Error())
}

func (e *UnmarshalingParamError) Unwrap() error {
	return e.Err
}

type RequiredParamError struct {
	ParamName string
}

func (e *RequiredParamError) Error() string {
	return fmt.Sprintf("Query argument %s is required, but not found", e.ParamName)
}

type RequiredHeaderError struct {
	ParamName string
	Err       error
}

func (e *RequiredHeaderError) Error() string {
	return fmt.Sprintf("Header parameter %s is required, but not found", e.ParamName)
}

func (e *RequiredHeaderError) Unwrap() error {
	return e.Err
}

type InvalidParamFormatError struct {
	ParamName string
	Err       error
}

func (e *InvalidParamFormatError) Error() string {
	return fmt.Sprintf("Invalid format for parameter %s: %s", e.ParamName, e.Err.Error())
}

func (e *InvalidParamFormatError) Unwrap() error {
	return e.Err
}

type TooManyValuesForParamError struct {
	ParamName string
	Count     int
}

func (e *TooManyValuesForParamError) Error() string {
	return fmt.Sprintf("Expected one value for %s, got %d", e.ParamName, e.Count)
}

// Handler creates http.Handler with routing matching OpenAPI spec.
func Handler(si ServerInterface) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{})
}

type ChiServerOptions struct {
	BaseURL          string
	BaseRouter       chi.Router
	Middlewares      []MiddlewareFunc
	ErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

// HandlerFromMux creates http.Handler with routing matching OpenAPI spec based on the provided mux.
func HandlerFromMux(si ServerInterface, r chi.Router) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{
		BaseRouter: r,
	})
}

func HandlerFromMuxWithBaseURL(si ServerInterface, r chi.Router, baseURL string) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{
		BaseURL:    baseURL,
		BaseRouter: r,
	})
}

// HandlerWithOptions creates http.Handler with additional options
func HandlerWithOptions(si ServerInterface, options ChiServerOptions) http.Handler {
	r := options.BaseRouter

	if r == nil {
		r = chi.NewRouter()
	}
	if options.ErrorHandlerFunc == nil {
		options.ErrorHandlerFunc = func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		}
	}
	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/v1/advisor/conversations", wrapper.ListAdvisorConversations)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/v1/advisor/conversations/{conversationId}", wrapper.GetAdvisorConversation)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/api/v1/advisor/conversations:ask", wrapper.AskAdvisor)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/v1/audit/head", wrapper.GetAuditHead)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/api/v1/audit/verify", wrapper.VerifyAuditChain)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/api/v1/auth/login", wrapper.Login)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/api/v1/auth/logout", wrapper.LogoutAuth)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/v1/auth/me", wrapper.GetCurrentSession)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/api/v1/auth/refresh", wrapper.RefreshAuth)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/v1/compliance/profiles", wrapper.ListComplianceProfiles)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/api/v1/compliance/profiles", wrapper.CreateComplianceProfile)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/v1/compliance/profiles/{profileId}/snapshots", wrapper.ListComplianceSnapshots)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/api/v1/compliance/profiles/{profileId}/snapshots", wrapper.GenerateComplianceSnapshot)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/api/v1/fleets/{fleetId}/insights:run", wrapper.RunFleetInsights)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/v1/insights", wrapper.ListInsights)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/api/v1/insights/{insightId}:dismiss", wrapper.DismissInsight)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/v1/license", wrapper.GetLicenseInfo)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/v1/reports", wrapper.ListReports)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/api/v1/reports/{reportId}:verify", wrapper.VerifyReport)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/v1/robots", wrapper.ListRobots)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/api/v1/robots", wrapper.CreateRobot)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/v1/robots/{robotId}", wrapper.GetRobot)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/v1/scans", wrapper.ListScans)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/api/v1/scans", wrapper.CreateScan)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/v1/scans/{sessionId}/progress", wrapper.StreamScanProgress)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/v1/tenants/current", wrapper.GetCurrentTenant)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/v1/webhooks", wrapper.ListWebhookEndpoints)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/api/v1/webhooks", wrapper.CreateWebhookEndpoint)
	})
	r.Group(func(r chi.Router) {
		r.Delete(options.BaseURL+"/api/v1/webhooks/{endpointId}", wrapper.DeleteWebhookEndpoint)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/v1/webhooks/{endpointId}", wrapper.GetWebhookEndpoint)
	})
	r.Group(func(r chi.Router) {
		r.Put(options.BaseURL+"/api/v1/webhooks/{endpointId}", wrapper.UpdateWebhookEndpoint)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/v1/webhooks/{endpointId}/deliveries", wrapper.ListWebhookDeliveries)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/healthz", wrapper.GetHealthz)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/readyz", wrapper.GetReadyz)
	})

	return r
}

